/**
 * Secret detection patterns for posttool/secret-handler.
 *
 * Two classes:
 *   - BOUNDED: high-confidence prefix patterns. Safe to redact in place
 *     because the prefix anchors the match (effectively zero FP rate).
 *   - CRITICAL: unbounded patterns where partial redaction can't be trusted.
 *     Trigger a full output GATE instead of in-place replacement.
 */

export interface BoundedPattern {
  readonly name: string;
  readonly re: RegExp;
}

export interface CriticalPattern {
  readonly name: string;
  readonly re: RegExp;
  readonly description: string;
}

export const BOUNDED_PATTERNS: readonly BoundedPattern[] = [
  // GitHub tokens — classic short-prefix and 2022+ fine-grained PAT format.
  // Audit (#1543): adding github_pat_ closes a documented FN.
  { name: 'github-pat', re: /\b(?:gh[oprsu]_[A-Za-z0-9]{36,255}|github_pat_[A-Za-z0-9_]{82})\b/g },
  // Anthropic API keys (sk-ant-* prefix; 32-128 char tail)
  { name: 'anthropic-key', re: /\bsk-ant-[A-Za-z0-9_-]{32,128}\b/g },
  // OpenAI project keys (sk-proj-*) — modern keys contain _ and - in tail.
  // Audit (#1543): classic openai-key tail charset rejected these → silent FN.
  { name: 'openai-project-key', re: /\bsk-proj-[A-Za-z0-9_-]{40,200}\b/g },
  // OpenAI classic keys (legacy sk-* — exactly 48 base62 chars post-prefix).
  // Tighter than the original 32-128 range → fewer FPs on doc strings.
  { name: 'openai-key', re: /\bsk-(?!ant-|proj-)[A-Za-z0-9]{48}\b/g },
  // AWS access key family — IAM user, STS session (very common in CI logs),
  // role, instance profile, group. Audit found ASIA/AROA/AIDA missing was
  // the highest-risk FN in CI traffic.
  { name: 'aws-access-key-id', re: /\b(?:AKIA|ASIA|AGPA|AIDA|AROA|AIPA|ANPA|ANVA|ABIA|ACCA)[A-Z0-9]{16}\b/g },
  // Slack tokens — bot/user/admin/refresh/Enterprise (xoxe), and Socket
  // Mode app-level (xapp). Min tail raised to 20 to cut short-string FPs.
  { name: 'slack-token', re: /\b(?:xox[abeprs]-[A-Za-z0-9-]{20,100}|xapp-\d-[A-Z0-9]+-\d+-[a-f0-9]{64})\b/g },
];

